style.css:
body {
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
  background: white;
}

* {
  box-sizing: border-box;
}

.studio-display {
  position: relative;
  width: 656px;
  height: 500px;
}
.studio-display .bezels {
  position: absolute;
  top: 0;
  width: 656px;
  height: 379px;
  background: #111;
  border-radius: 5px;
}
.studio-display .bezels .screen {
  position: absolute;
  top: 14px;
  bottom: 14px;
  left: 14px;
  right: 14px;
  background: #6d6d6d;
  overflow: hidden;
}
.studio-display .bezels .screen img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}
.studio-display .stand {
  position: relative;
  top: 379px;
  left: 248px;
  width: 160px;
  height: 121px;
}
.studio-display .stand .body {
  width: 160px;
  height: 114px;
  background: red;
  background: linear-gradient(180deg, #B5B6B8 0%, #D5D6D8 43.02%, #D8D9DB 62.32%, #D7D7D7 80.08%, #CBCCCE 92.05%, #D6D7D9 94.15%, #EEEFF1 95.45%, #E7E9ED 97.1%, #BABBBD 98.4%, #606163 99.4%, #696A6C 100%);
}
.studio-display .stand .body .hole {
  position: absolute;
  width: 48px;
  height: 48px;
  left: 56px;
  top: -28px;
  border-radius: 50%;
  background: linear-gradient(180deg, #FFFFFF 0%, #C3C4C6 66.72%, #E4E5E7 100%);
}
.studio-display .stand .body .hole:after {
  content: "";
  display: block;
  margin: 4px;
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: #fff;
}
.studio-display .stand .foot {
  width: 160px;
  height: 6px;
  background: linear-gradient(90deg, #EFEFEF 0%, #B4B5B7 0.91%, #98999B 1.57%, #B3B4B6 2.29%, #E5E5E5 2.87%, #E9EAEC 4.65%, #E2E3E5 6.68%, #D2D3D5 9.15%, #DBDCDE 30%, #DBDCDE 50.41%, #DBDCDE 70%, #D2D3D5 90.94%, #E2E3E5 93.18%, #E7E8EA 94.71%, #E5E5E5 97.4%, #B3B4B6 97.99%, #98999B 98.74%, #B4B5B7 99.44%, #EFEFEF 100%);
}
.studio-display .stand .foot:before, .studio-display .stand .foot:after {
  content: "";
  position: absolute;
  bottom: 0;
  width: 16px;
  height: 1px;
  background: black;
}
.studio-display .stand .foot:before {
  left: 5px;
}
.studio-display .stand .foot:after {
  right: 5px;
}
